class Container<T> where T: Serializable {
    field ArrayRef[T] $items = [];

    method add(T $item) -> Void {
        push @{$items}, $item;
    }

    method get_all() -> ArrayRef[T] {
        return $items;
    }

    method find(CodeRef[T, Bool] $predicate) -> Optional[T] {
        for my $item (@{$items}) {
            return $item if $predicate->($item);
        }
        return undef;
    }
}
